                                    const slotKey = String(cell.getAttribute('data-scene-popup-time-range') || '').trim();
                                    const current = !!launchPeriodGridState?.[dayKey]?.[slotKey];
                                    dragState = { active: true, next: !current };
                                    applyFromCell(cell, !current);
                                    timeTemplate = 'custom';
                                    timeRecommendPreset = '';
